import { useEffect, useState } from 'react';
import { Table, Card,  Button, Select } from 'antd';
import data from './data-v2.2';
import './index.css';

const check_Keys = ["µĀĖÕ┐āńø¤ń║”1", "µĀĖÕ┐āńø¤ń║”2","ķÖäÕŖĀńø¤ń║”1","ķÖäÕŖĀńø¤ń║”2", "ķÖäÕŖĀńø¤ń║”3","ÕŁŚµ«Ą", "ńē╣Ķ┤©ń▒╗Õ×ŗ"];
const rank = ["I","II","III","IV","V","VI"];

const hxmy = ["ńéÄ", "ĶÉ©Õ░öĶ┤Ī", "ń╗┤ÕżÜÕł®õ║Ü", "Ķ░óµŗēµĀ╝", "µŗēńē╣Õģ░", "ķś┐µłłÕ░ö", "ÕÅÖµŗēÕÅż", "ÕŹĪĶź┐ń▒│Õ░ö"]
const my = ["ń▓ŠÕćå", "Ķ┐ģµŹĘ", "ńüĄÕĘ¦", "Õźźµ£»", "ÕØÜÕ«ł", "ÕŖ®ÕŖø", "Ķ┐£Ķ¦ü", "ÕźćĶ┐╣", "µŖĢĶĄäõ║║", "ń¬üĶóŁ", "õĖŹÕ▒ł", "Ķ░āÕÆī", "ÕŹÅķś▓Õ╣▓Õæś", "ńŗ¼ĶĪī", "ń╗ØµŖĆ"];
const zd = ['ĶÄĘÕŠŚµŚČ', 'õ╝æµĢ┤µ£¤ń╗ōµØ¤µŚČ', 'Õö«Õć║µŚČ', 'µłśµ¢ŚõĖŁ', 'Ķ┐øÕģźõ╝æµĢ┤µ£¤µŚČ', 'Õ╝ĆÕÉ»µŖĆĶāĮµŚČ', 'ķā©ńĮ▓µŚČ', 'Ķ┤Łõ╣░', 'µłśµ¢ŚÕ╝ĆÕ¦ŗµŚČ']

function App() {
    const [originList, setOriginList] = useState([]); // ÕÄ¤Õ¦ŗµĢ░µŹ«ÕłŚĶĪ©
    const [selectList, setSelectList] = useState([]); // ńŁøķĆēÕÉÄÕłŚĶĪ©
    const [trait, setTrait] = useState([]); //ń▒╗Õ×ŗńŁøķĆē
    const [selectOne, setSelectOne] = useState({}); //ķĆēµŗ®Õ╣▓Õæś
    const [activeFilter, setActiveFilter] = useState([]); //ńŁøķĆēķĪ╣
    const [operatorShow, setOperatorShow] = useState([]); //Ķ«ŠńĮ«µēŗµ£║ń½»Õ╣▓ÕæśĶ»”µāģķÜÉĶŚÅ

    
    const selectOneS = (item) => {
        setSelectOne(item)
        setOperatorShow("show")
        document.body.style.overflow = 'hidden';
    }
    const selectOther = () => {
        setOperatorShow("hide");
        document.body.style.overflow = 'unset';
    }

    const handleFilterChange = (filterTag, type) => {
        let tags = [];
        switch(type){
            case 0:
                tags = rank;
                break;
            case 1:
                tags = hxmy;
                break;
            case 2:
                tags = my;
                break;
            case 3:
                tags = trait;
                break;
            case 4:
                tags = zd;
                break;
            default:
                tags = rank;
                break;
        }
        let newFilter = [...activeFilter];
        if(filterTag === "all") {
            newFilter = newFilter.filter(item => !tags.includes(item));
        } else if(newFilter.includes(filterTag) ){
            newFilter = newFilter.filter(item => item !== filterTag);
        } else {
            newFilter = newFilter.filter(item => !tags.includes(item));
            newFilter.push(filterTag)
        }
        setActiveFilter(newFilter);
    }

    useEffect(() => {
        const filterzd = [];
        const filterTrait = [];
        const processList = data.map((item, index) => {
            const filterTag = [];

            const my = [];
            const zd = [];
            check_Keys.forEach((key) => {
                item[key] && filterTag.push(item[key]);
                if(key !== "ÕŁŚµ«Ą" && key !== "ńē╣Ķ┤©ń▒╗Õ×ŗ" && item[key]){
                    my.push(item[key])
                } else {
                    zd.push(item[key])
                }
                
                if(key === "ÕŁŚµ«Ą"){
                    if(item[key] && !filterzd.includes(item[key])){
                        filterzd.push(item[key]);
                    } 
                }  
                if(key === "ńē╣Ķ┤©ń▒╗Õ×ŗ"){
                    if(item[key] && !filterTrait.includes(item[key])){
                        filterTrait.push(item[key]);
                    } 
                }  
            });
            filterTag.push(item["ķśČµĢ░"]);
            setTrait(filterTrait);
            return {
                key: index,
                level: item["ķśČµĢ░"],
                name: item["Õ╣▓ÕæśÕÉŹ"],
                coreCovenant1: item["µĀĖÕ┐āńø¤ń║”1"],
                coreCovenant2: item["µĀĖÕ┐āńø¤ń║”2"],
                covenant1: item["ķÖäÕŖĀńø¤ń║”1"],
                covenant2: item["ķÖäÕŖĀńø¤ń║”2"],
                traitType: item["ńē╣Ķ┤©ń▒╗Õ×ŗ"],
                traitDesc: item["ńē╣Ķ┤©µÅÅĶ┐░"],
                filterTag,
                my,
                zd
            }
        });
        setOriginList(processList);
        setSelectList(processList);
    }, []);

    useEffect(() => {
        if(activeFilter.length === 0){
            setSelectList(originList);
            return;
        }
        let selectList = originList.filter((item) => {
            return activeFilter.every((tag) => {
                if(item.filterTag.includes(tag)){
                    return true;
                }
            });
        });
        setSelectList(selectList)
        setSelectOne(selectList[0] || {})
    }, [originList, activeFilter]);
    const setOption = (list) => {
        const options = [];
        list.forEach(element => {
            options.push({
                value: element,
                label: element
            })
        });
        return options;
    }
    return (
    <div id="wx-excel-page">
        {/* <Table dataSource={data} columns={columns} /> */}
        <div className="filter-container">
            <div className="desktop">
                <div className="filter-list">{ rank.map((item) => {
                    return <Button key={"filter-" + item } className={"filter-one " + (activeFilter.includes(item) ? "filter-one-select" : "")} onClick={() => handleFilterChange(item, 0)}>{item}</Button>
                }) }</div>
                <div className="filter-list">{ hxmy.map((item) => {
                    return <Button key={"filter-" + item } className={"filter-one " + (activeFilter.includes(item) ? "filter-one-select" : "")} onClick={() => handleFilterChange(item, 1)}>{item}</Button>
                }) }</div>
                <div className="filter-list">{ my.map((item) => {
                    return <Button key={"filter-" + item } className={"filter-one " + (activeFilter.includes(item) ? "filter-one-select" : "")} onClick={() => handleFilterChange(item, 2)} >{item}</Button>
                }) }</div>
                <div className="filter-list">{ trait.map((item) => {
                    return <Button key={"filter-" + item } className={"filter-one " + (activeFilter.includes(item) ? "filter-one-select" : "")} onClick={() => handleFilterChange(item, 3)} >{item}</Button>
                }) }</div>
                <div className="filter-list">{ zd.map((item) => {
                    return <Button key={"filter-" + item } className={"filter-one " + (activeFilter.includes(item) ? "filter-one-select" : "")} onClick={() => handleFilterChange(item, 4)} >{item}</Button>
                }) }
                    <Button className="filter-one" onClick={() => setActiveFilter([])} >µĖģķÖż</Button>
                </div>
            </div>
            <div className="mobile">
                <Select className="filter-select" onChange={item => handleFilterChange(item, 0)} options={setOption(["all", ...rank])} defaultValue="all"></Select>
                <Select className="filter-select" onChange={item => handleFilterChange(item, 1)} options={setOption(["all", ...hxmy])} defaultValue="all"></Select>
                <Select className="filter-select" onChange={item => handleFilterChange(item, 2)} options={setOption(["all", ...my])} defaultValue="all"></Select>
                <Select className="filter-select" onChange={item => handleFilterChange(item, 3)} options={setOption(["all", ...trait])} defaultValue="all"></Select>
                <Select className="filter-select" onChange={item => handleFilterChange(item, 4)} options={setOption(["all", ...zd])} defaultValue="all"></Select>
                <Button className="filter-one" onClick={() => setActiveFilter([])} >µĖģķÖż</Button>
            </div>
        </div>
        <div className='operator-show'>
            <div className='operator-left'>
                <div className="operator-list custom-scrollbar">
                    { selectList.map((item, i) => {
                        return <div  key={"select-" + i} className={"operator-one " + (selectOne.name === item.name ? "operator-one-select " : "") + "border-level-" + item.level} onClick={(e) => {e.stopPropagation(); selectOneS(item)}}>
                            <div><img alt={item.name} src={process.env.PUBLIC_URL +"/images/Õż┤ÕāÅ/Õż┤ÕāÅ_" + item.name + ".png"}/></div>
                            <div>{item.name}</div>    
                        </div>
                    })}
                    <div className="operator-one none">
                        <div></div>
                        <div></div>    
                    </div>
                </div>
            </div>
            <div className='operator-right desktop'>
                <div className={"selct-one-detail border-level-" + (selectOne.level || 0)}>
                    {/*Õ╣▓ÕæśµÅÅĶ┐░*/}
                    {selectOne.name && <div>
                        <img alt={selectOne.name} src={process.env.PUBLIC_URL +"/images/Õż┤ÕāÅ/Õż┤ÕāÅ_" + selectOne.name + ".png"}/>
                        <h2>{selectOne.name}</h2>
                        <p>ķśČµĢ░’╝Ü{selectOne.level}</p>
                        <p>ńø¤ń║”’╝Ü{selectOne.my ? (selectOne.my.map(item => (item + " ")) + " ") : ""}</p>
                        <p>ńē╣Ķ┤©ń▒╗Õ×ŗ’╝Ü{selectOne.traitType}</p>
                        <p>ńē╣Ķ┤©µÅÅĶ┐░’╝Ü{selectOne.traitDesc}</p>
                    </div>  
                    }
                </div>    
            </div>
            { operatorShow === "show" && <div className='operator-right mobile'>
                <div className='operator-hide' onClick={() => selectOther()}></div>
                <div className={"selct-one-detail border-level-" + (selectOne.level || 0)} onClick={() => selectOther()}>
                    {/*Õ╣▓ÕæśµÅÅĶ┐░*/}
                    {selectOne.name && <div>
                        <img alt={selectOne.name} src={process.env.PUBLIC_URL +"/images/Õż┤ÕāÅ/Õż┤ÕāÅ_" + selectOne.name + ".png"}/>
                        <h2>{selectOne.name}</h2>
                        <p>ķśČµĢ░’╝Ü{selectOne.level}</p>
                        <p>ńø¤ń║”’╝Ü{selectOne.my ? (selectOne.my.map(item => (item + " ")) + " ") : ""}</p>
                        <p>ńē╣Ķ┤©ń▒╗Õ×ŗ’╝Ü{selectOne.traitType}</p>
                        <p>ńē╣Ķ┤©µÅÅĶ┐░’╝Ü{selectOne.traitDesc}</p>
                    </div>  
                    }
                </div>    
            </div>}
        </div>
        
    </div>
  );
}

export default App;
 