import { useEffect, useState } from 'react';
import { InputNumber  } from 'antd';
import data from './data';
import './index.css';

const keysMatch = {
        "ńø¤ń║”":"name",
        "µ┐Ćµ┤╗õ║║µĢ░": "num",
        "µĢłµ×£1": "effect1",
        "µĢłµ×£Õģ¼Õ╝Å1": "formula1",
        "µĢłµ×£2": "effect2",
        "µĢłµ×£3": "effect3",
        "µēĆÕ▒×Õ╣▓Õæś": "operators",
        "ń▒╗Õ×ŗ": "type",
}
function App() {
    const [originList, setOriginList] = useState([]); // ÕÄ¤Õ¦ŗµĢ░µŹ«ÕłŚĶĪ©
    const [selectList, setSelectList] = useState([]); // ńŁøķĆēÕÉÄÕłŚĶĪ©
    const [selectOne, setSelectOne] = useState({}); //ķĆēµŗ®
    const [allianceShow, setallianceShow] = useState([]); //Ķ«ŠńĮ«µēŗµ£║ń½»Õ╣▓ÕæśĶ»”µāģķÜÉĶŚÅ
    const [layers, setLayers] = useState(0); //Õ▒éµĢ░
    
    const selectOneS = (item) => {
        setLayers(0);
        setSelectOne(item)
        setallianceShow("show")
        document.body.style.overflow = 'hidden';
    }
    const selectOther = () => {
        setallianceShow("hide");

        document.body.style.overflow = 'unset';
    }

    useEffect(() => {
        const list = [];
        data.forEach((item, index) => {
            const one = {};
            Object.keys(keysMatch).forEach((key) => {
                
                one[keysMatch[key]] = item[key]
            });
            list.push(one);
        });
        setOriginList(list);
        setSelectList(list);
    }, []);
    return (
    <div id="wx-excel-page">
        <div className='alliance-show'>
            <div className='alliance-left'>
                <div className="alliance-list custom-scrollbar">
                  <div className="alliance-list-hx">
                      { selectList.map((item, i) => {
                        if(item.type === "µĀĖÕ┐ā"){
                        return <div  key={"select-" + i} className={"alliance-one " + (selectOne.name === item.name ? "alliance-one-select " : "")} onClick={(e) => {e.stopPropagation(); selectOneS(item)}}>
                            <div><img className="alliance-img" alt={item.name} src={process.env.PUBLIC_URL + "/images/ńø¤ń║”/" + item.name + ".png"}/></div>
                            <div>{item.name}</div>    
                        </div>
                        }
                      })}
                  </div>
                  <div className="alliance-list-fj">
                    { selectList.map((item, i) => {
                      if(item.type === "ķÖäÕŖĀ"){
                        return <div  key={"select-" + i} className={"alliance-one " + (selectOne.name === item.name ? "alliance-one-select " : "")} onClick={(e) => {e.stopPropagation(); selectOneS(item)}}>
                            <div><img className="alliance-img" alt={item.name} src={process.env.PUBLIC_URL + "/images/ńø¤ń║”/" + item.name + ".png"}/></div>
                            <div>{item.name}</div>    
                        </div>
                      }
                    })}
                  </div>
                    
                    <div className="alliance-one none">
                        <div></div>
                        <div></div>    
                    </div>
                </div>
            </div>
            <div className='alliance-right desktop'>
                <div className="selct-one-detail">
                    {/*Õ╣▓ÕæśµÅÅĶ┐░*/}
                    {selectOne.name && <div>
                        
                        <h2>{selectOne.name}</h2>
                        <div className="alliance-layers">
                          <InputNumber defaultValue={0} value={layers} onClick={ (e) => e.stopPropagation()}onChange={(value) => { setLayers(Number((value?value:0).toFixed(0)))}} max={999} min={0}/><div className='ml-5'>Õ▒é</div>
                        </div>
                        {Object.keys(keysMatch).map((key) => {
                            if(!selectOne[keysMatch[key]]) return null;
                            let text = selectOne[keysMatch[key]];
                            switch(key){
                                case "ńø¤ń║”":
                                  return null;
                                case "µēĆÕ▒×Õ╣▓Õæś":
                                    return <div className='operator-list-s' key={'operator-list-s-' + selectOne.name} >
                                      {text.map((operator) => {
                                        return <div key={"operator-list-s-" + operator} className='operator-item'>
                                            <img alt={operator} src={process.env.PUBLIC_URL + "/images/Õż┤ÕāÅ/Õż┤ÕāÅ_" + operator + ".png"}/>
                                        </div>
                                      })}
                                    </div>
                                  case "ń▒╗Õ×ŗ":
                                    return null;
                                  case "µ┐Ćµ┤╗õ║║µĢ░":
                                    return <p key={key}>{key}’╝Ü{text}</p>
                                default:
                                      if(text instanceof Object){
                                        return <p className="text-left" key={key}>{key}’╝Ü{text[2] ? text[0].replace("Y", Number((text[1](layers).toFixed(0)))).replace("Z", text[2](layers)) : text[0].replace("Y", Number((text[1](layers).toFixed(0))))}</p>
                                      } else {
                                        return <p className="text-left" key={key}>{key}’╝Ü{text}</p>
                                      }
                                    
                            }
                        })}
                    </div>  
                    }
                </div>    
            </div>
            { allianceShow === "show" && <div className='alliance-right mobile'>
                <div className='alliance-hide' onClick={() => selectOther()}></div>
                <div className="selct-one-detail" onClick={() => selectOther()}>
                    {/*Õ╣▓ÕæśµÅÅĶ┐░*/}
                    {selectOne.name && <div>
                        <h2>{selectOne.name}</h2>
                      <h2><InputNumber defaultValue={0} value={layers} onClick={ (e) => e.stopPropagation()} onChange={(value) => { setLayers(Number((value?value:0).toFixed(0)))}} max={999} min={0}/><text className='ml-5'>Õ▒é</text></h2>
                        {Object.keys(keysMatch).map((key) => {
                            if(!selectOne[keysMatch[key]]) return null;
                            let text = selectOne[keysMatch[key]];
                            switch(key){
                                case "ńø¤ń║”":
                                  return null;
                                case "µēĆÕ▒×Õ╣▓Õæś":
                                    return <div className='operator-list-s' key={'operator-list-s-' + selectOne.name} >
                                      {text.map((operator) => {
                                        return <div key={"operator-list-s-" + operator} className='operator-item'>
                                            <img alt={operator} src={process.env.PUBLIC_URL + "/images/Õż┤ÕāÅ/Õż┤ÕāÅ_" + operator + ".png"}/>
                                        </div>
                                      })}
                                    </div>
                                  case "ń▒╗Õ×ŗ":
                                    return null;
                                  case "µ┐Ćµ┤╗õ║║µĢ░":
                                    return <p key={key}>{key}’╝Ü{text}</p>
                                default:
                                      if(text instanceof Object){
                                        return <p className="text-left" key={key}>{key}’╝Ü{text[2] ? text[0].replace("Y", Number((text[1](layers).toFixed(0)))).replace("Z", text[2](layers)) : text[0].replace("Y", Number((text[1](layers).toFixed(0))))}</p>
                                      } else {
                                        return <p className="text-left" key={key}>{key}’╝Ü{text}</p>
                                      }
                                    
                            }
                        })}
                    </div>  
                    }
                </div>    
            </div>}
        </div>
        
    </div>
  );
}

export default App;
 