                            <div><img alt={item.name} src={process.env.PUBLIC_URL + "/images/ńŁ¢ńĢź/ÕŹ½µłŹÕŹÅĶ««’╝Üńø¤ń║”_ńŁ¢ńĢźÕÅæĶĄĘõ║║_" + item.name + ".png"}/></div>
